<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0,user-scalable=no">
<title>HELLWING - Rail Shooter</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{background:#000;display:flex;justify-content:center;align-items:center;width:100vw;height:100vh;overflow:hidden;font-family:'Courier New',monospace;user-select:none}
#wrap{position:relative;width:1280px;height:720px;max-width:100vw;max-height:100vh;aspect-ratio:16/9}
canvas{width:100%;height:100%;display:block;image-rendering:pixelated}
#hud{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;display:flex;flex-direction:column;justify-content:space-between;padding:12px 20px;color:#ff4422;font-size:20px;font-weight:bold;text-shadow:0 0 8px #ff0000}
