.dpad button{position:absolute;width:44px;height:44px;background:rgba(255,34,0,.25);border:2px solid rgba(255,68,34,.5);color:#ff4422;font-size:18px;font-weight:bold;border-radius:8px}
.dpad .du{top:0;left:48px}.dpad .dd{bottom:0;left:48px}.dpad .dl{top:48px;left:0}.dpad .dr{top:48px;right:0}
