<body>
<div id="wrap">
<canvas id="c" width="1280" height="720"></canvas>
<div id="hud">
<div class="hrow"><span id="hs">SCORE: 000000</span><span id="ht">SOULS: 0</span></div>
<div id="reticle"></div>
<div class="hrow"><span id="hsh">SHIELD: ██████████</span><span id="hb">BOMBS: 3</span></div>
</div>
<div id="overlay"><h1>DAMNED</h1><p id="finalScore">Score: 0</p><button id="restartBtn">Descend Again</button></div>
<div id="mobile-controls">
<div class="dpad"><button class="du" data-k="up">▲</button><button class="dd" data-k="down">▼</button><button class="dl" data-k="left">◄</button><button class="dr" data-k="right">►</button></div>
<div class="abcbtns"><button class="ba" data-k="a">A</button><button class="bb" data-k="b">B</button><button class="bc" data-k="c">C</button></div>
</div>
</div>
<script>
const W=1280,H=720,cx=W/2,cy=H/2;
const canvas=document.getElementById('c'),ctx=canvas.getContext('2d');
const keys={up:false,down:false,left:false,right:false,a:false,b:false,c:false};
let lastTapLeft=0,lastTapRight=0,barrelRoll=0,barrelDir=0,iFrames=0;

document.addEventListener('keydown',e=>{
const m={ArrowUp:'up',ArrowDown:'down',ArrowLeft:'left',ArrowRight:'right',KeyA:'a',KeyB:'b',KeyC:'c',Space:'a'};
const k=m[e.code];if(k){keys[k]=true;e.preventDefault();
if(k==='left'){const n=Date.now();if(n-lastTapLeft<300&&barrelRoll<=0){barrelRoll=20;barrelDir=-1;iFrames=20}lastTapLeft=n}
if(k==='right'){const n=Date.now();if(n-lastTapRight<300&&barrelRoll<=0){barrelRoll=20;barrelDir=1;iFrames=20}lastTapRight=n}
}});
document.addEventListener('keyup',e=>{
const m={ArrowUp:'up',ArrowDown:'down',ArrowLeft:'left',ArrowRight:'right',KeyA:'a',KeyB:'b',KeyC:'c',Space:'a'};
const k=m[e.code];if(k)keys[k]=false});

document.querySelectorAll('#mobile-controls button').forEach(b=>{
const k=b.dataset.k;
b.addEventListener('touchstart',e=>{e.preventDefault();keys[k]=true});
b.addEventListener('touchend',e=>{e.preventDefault();keys[k]=false});
});

function proj(x,y,z,fov=300,vd=300){
const d=vd+z;if(d<=1)return null;const f=fov/d;return{x:x*f+cx,y:y*f+cy,s:f}}
function rotX(v,a){const c=Math.cos(a),s=Math.sin(a);return[v[0],v[1]*c-v[2]*s,v[1]*s+v[2]*c]}
function rotY(v,a){const c=Math.cos(a),s=Math.sin(a);return[v[0]*c-v[2]*s,v[1],v[0]*s+v[2]*c]}
function rotZ(v,a){const c=Math.cos(a),s=Math.sin(a);return[v[0]*c-v[1]*s,v[0]*s+v[1]*c,v[2]]}
function transform(v,rx,ry,rz,tx,ty,tz){let p=rotX(v,rx);p=rotY(p,ry);p=rotZ(p,rz);return[p[0]+tx,p[1]+ty,p[2]+tz]}
function lerp(a,b,t){return a+(b-a)*t}

const shipVerts=[[0,0,40],[-25,0,-20],[25,0,-20],[0,-15,-15],[0,10,-15],[-10,0,-10],[10,0,-10]];
const shipFaces=[[0,5,3,'#cc2200'],[0,3,6,'#aa1100'],[0,4,5,'#881100'],[0,6,4,'#771100'],[5,1,3,'#ff3300'],[6,3,2,'#ff3300'],[5,4,1,'#aa0000'],[6,2,4,'#aa0000']];
const enemyVerts=[[0,15,0],[15,0,15],[15,0,-15],[-15,0,-15],[-15,0,15],[0,-15,0]];
const enemyFaces=[[0,1,2,'#880044'],[0,2,3,'#660033'],[0,3,4,'#880044'],[0,4,1,'#660033'],[5,2,1,'#440022'],[5,3,2,'#330011'],[5,4,3,'#440022'],[5,1,4,'#330011']];

let state,player,entities,score,bombs,shield,fireCool,gameZ,bossMode,boss,souls;
let stars,pillars,fireParticles;

function init(){
state='play';score=0;bombs=3;shield=100;fireCool=0;gameZ=0;bossMode=false;boss=null;souls=0;
player={x:0,y:0,z:-100,rx:0,ry:0,rz:0,banking:0,pitching:0};
entities=[];
stars=Array.from({length:200},()=>({x:(Math.random()-0.5)*4000,y:(Math.random()-0.5)*3000,z:Math.random()*4000}));
pillars=[];fireParticles=[];
for(let i=0;i<30;i++)pillars.push({x:(Math.random()-0.5)*2000,z:500+Math.random()*5000,h:100+Math.random()*300,w:20+Math.random()*40});
document.getElementById('overlay').style.display='none';
updateHUD();
}

function updateHUD(){
document.getElementById('hs').textContent='SCORE: '+score.toString().padStart(6,'0');
document.getElementById('ht').textContent='SOULS: '+souls;
const bars=Math.max(0,Math.ceil(shield/10));
document.getElementById('hsh').textContent='SHIELD: '+'█'.repeat(bars)+'░'.repeat(10-bars);
document.getElementById('hb').textContent='BOMBS: '+bombs;
}

function spawnEnemy(){
const ex=(Math.random()-0.5)*800,ey=(Math.random()-0.5)*400;
entities.push({type:'enemy',x:ex,y:ey,z:3000+Math.random()*1000,vz:-600-Math.random()*200,hp:15,rx:0,ry:0,sinOff:Math.random()*6.28,t:0});
}
function spawnBoss(){
bossMode=true;
boss={x:0,y:0,z:2000,hp:200,maxHp:200,phase:0,t:0,rx:0,ry:0,size:3};
entities.push(boss);
}

function fireLaser(){
if(fireCool>0)return;fireCool=8;
entities.push({type:'laser',x:player.x-15,y:player.y,z:player.z+40,vz:2500,life:80});
entities.push({type:'laser',x:player.x+15,y:player.y,z:player.z+40,vz:2500,life:80});
}
function fireBomb(){
if(bombs<=0||fireCool>3)return;bombs--;
entities.push({type:'bomb',x:player.x,y:player.y,z:player.z+30,vz:1500,life:60,radius:0});
updateHUD();
}

function drawPoly(pts,col){
if(pts.length<3)return;ctx.fillStyle=col;ctx.strokeStyle='#000';ctx.lineWidth=1;
ctx.beginPath();ctx.moveTo(pts[0].x,pts[0].y);
for(let i=1;i<pts.length;i++)ctx.lineTo(pts[i].x,pts[i].y);
ctx.closePath();ctx.fill();ctx.stroke();
}

function renderModel(verts,faces,rx,ry,rz,tx,ty,tz,sc=1){
const wv=verts.map(v=>transform([v[0]*sc,v[1]*sc,v[2]*sc],rx,ry,rz,tx,ty,tz));
let polys=[];
for(let f of faces){
const pts=f.slice(0,-1).map(i=>wv[i]);
const pp=pts.map(p=>proj(p[0],p[1],p[2]));
if(pp.some(p=>!p))continue;
const avgz=pts.reduce((s,p)=>s+p[2],0)/pts.length;
polys.push({pts:pp,col:f[f.length-1],z:avgz});
}
return polys;
}

let spawnTimer=0,bossTimer=0,frame=0;
function update(dt){
if(state!=='play')return;
frame++;gameZ+=800*dt;
if(fireCool>0)fireCool--;
if(barrelRoll>0)barrelRoll--;
if(iFrames>0)iFrames--;

// Input
const spd=500*dt;
player.banking=0;player.pitching=0;
if(keys.left){player.x-=spd;player.banking=1}
if(keys.right){player.x+=spd;player.banking=-1}
if(keys.up){player.y-=spd;player.pitching=-1}
if(keys.down){player.y+=spd;player.pitching=1}
if(keys.a)fireLaser();
if(keys.b)fireBomb();

player.x=Math.max(-400,Math.min(400,player.x));
player.y=Math.max(-280,Math.min(280,player.y));
player.rz=lerp(player.rz,player.banking*0.7+(barrelRoll>0?barrelDir*Math.PI*2*(barrelRoll/20):0),0.15);
player.rx=lerp(player.rx,player.pitching*0.3,0.1);

// Spawning
if(!bossMode){
spawnTimer+=dt;bossTimer+=dt;
if(spawnTimer>1.5){spawnTimer=0;spawnEnemy();if(Math.random()>0.5)spawnEnemy()}
if(bossTimer>45)spawnBoss();
}

// Fire particles (environmental)
if(frame%3===0)fireParticles.push({x:(Math.random()-0.5)*1500,y:200+Math.random()*100,z:2000+Math.random()*2000,life:60,vy:-2-Math.random()*3});
for(let i=fireParticles.length-1;i>=0;i--){
fireParticles[i].life--;fireParticles[i].y+=fireParticles[i].vy;fireParticles[i].z-=800*dt;
if(fireParticles[i].life<=0||fireParticles[i].z<-200)fireParticles.splice(i,1);
}

// Update entities
for(let i=entities.length-1;i>=0;i--){
const e=entities[i];
if(e.type==='enemy'){
e.z+=e.vz*dt;e.t+=dt;e.rx+=0.04;e.ry+=0.03;
e.x+=Math.sin(e.t*2+e.sinOff)*4;
if(e.z<-300){entities.splice(i,1);continue}
if(e.hp<=0){score+=100;souls++;entities.splice(i,1);
for(let k=0;k<8;k++)fireParticles.push({x:e.x+(Math.random()-0.5)*50,y:e.y+(Math.random()-0.5)*50,z:e.z,life:30,vy:(Math.random()-0.5)*5});
updateHUD();continue}
// Collision with player
if(iFrames<=0){const dx=player.x-e.x,dy=player.y-e.y,dz=player.z-e.z;
if(dx*dx+dy*dy+dz*dz<6000){shield-=15;e.hp=0;updateHUD();if(shield<=0)gameOver()}}
}
if(e===boss){
e.t+=dt;e.rx=Math.sin(e.t)*0.3;e.ry=e.t*0.5;
e.x=Math.sin(e.t*0.7)*300;e.y=Math.sin(e.t*1.1)*150;
if(e.hp<=0){score+=2000;souls+=10;bossMode=false;boss=null;bossTimer=0;entities.splice(i,1);
for(let k=0;k<30;k++)fireParticles.push({x:e.x+(Math.random()-0.5)*200,y:e.y+(Math.random()-0.5)*200,z:e.z,life:50,vy:(Math.random()-0.5)*8});
updateHUD();continue}
// Boss fires
if(frame%40===0){entities.push({type:'elaser',x:e.x,y:e.y,z:e.z,vz:-1800,life:80})}
}
if(e.type==='laser'){
e.z+=e.vz*dt;e.life--;
if(e.life<=0){entities.splice(i,1);continue}
// Hit enemies
for(let j=entities.length-1;j>=0;j--){
const t=entities[j];if(t.type!=='enemy'&&t!==boss)continue;
const dx=e.x-t.x,dy=e.y-t.y,dz=e.z-t.z;const r=t===boss?8000:3500;
if(dx*dx+dy*dy+dz*dz<r){t.hp-=10;entities.splice(i,1);break}}
}
if(e.type==='elaser'){
e.z+=e.vz*dt;e.life--;
if(e.life<=0){entities.splice(i,1);continue}
if(iFrames<=0){const dx=player.x-e.x,dy=player.y-e.y,dz=player.z-e.z;
if(dx*dx+dy*dy+dz*dz<5000){shield-=10;entities.splice(i,1);updateHUD();if(shield<=0)gameOver()}}
}
if(e.type==='bomb'){
e.z+=e.vz*dt;e.life--;e.radius+=5;
if(e.life<=0){entities.splice(i,1);continue}
for(let j=entities.length-1;j>=0;j--){
const t=entities[j];if(t.type!=='enemy'&&t!==boss)continue;
const dx=e.x-t.x,dy=e.y-t.y,dz=e.z-t.z;
if(dx*dx+dy*dy+dz*dz<(e.radius*e.radius*100)){t.hp-=5}}
}
}
}

function gameOver(){
state='over';
document.getElementById('finalScore').textContent='Score: '+score+' | Souls: '+souls;
document.getElementById('overlay').style.display='flex';
}

function render(){
ctx.fillStyle='#0a0000';ctx.fillRect(0,0,W,H);

// Hellish sky gradient
const grd=ctx.createLinearGradient(0,0,0,H);
grd.addColorStop(0,'#1a0000');grd.addColorStop(0.4,'#330500');grd.addColorStop(0.7,'#551100');grd.addColorStop(1,'#220000');
ctx.fillStyle=grd;ctx.fillRect(0,0,W,H);

// Stars (embers)
for(let s of stars){
s.z-=600*(1/60);if(s.z<0){s.z=4000;s.x=(Math.random()-0.5)*4000;s.y=(Math.random()-0.5)*3000}
const p=proj(s.x,s.y,s.z);if(!p)continue;
const bright=Math.random()>0.5?'#ff6633':'#ffaa00';
ctx.fillStyle=bright;ctx.globalAlpha=Math.min(1,p.s*2);ctx.fillRect(p.x,p.y,Math.max(1,p.s*3),Math.max(1,p.s*3));ctx.globalAlpha=1;
}

// Lava ground plane
ctx.fillStyle='#441100';
for(let gz=-200;gz<4000;gz+=200){
const lx=-1500,rx2=1500,gy=250;
const p1=proj(lx,gy,gz),p2=proj(rx2,gy,gz),p3=proj(rx2,gy,gz+200),p4=proj(lx,gy,gz+200);
if(!p1||!p2||!p3||!p4)continue;
const flicker=Math.sin(frame*0.1+gz*0.01)*20;
const r=Math.min(255,68+flicker),g=Math.max(0,17+flicker/3);
ctx.fillStyle=`rgb(${r|0},${g|0},0)`;
ctx.beginPath();ctx.moveTo(p1.x,p1.y);ctx.lineTo(p2.x,p2.y);ctx.lineTo(p3.x,p3.y);ctx.lineTo(p4.x,p4.y);ctx.closePath();ctx.fill();
}

// Pillars (stone columns)
for(let pl of pillars){
let pz=((pl.z-gameZ%5000)+5000)%5000;
const p1=proj(pl.x-pl.w,250,pz),p2=proj(pl.x+pl.w,250,pz);
const p3=proj(pl.x+pl.w,250-pl.h,pz),p4=proj(pl.x-pl.w,250-pl.h,pz);
if(!p1||!p2||!p3||!p4)continue;
ctx.fillStyle='#2a1508';ctx.beginPath();ctx.moveTo(p1.x,p1.y);ctx.lineTo(p2.x,p2.y);ctx.lineTo(p3.x,p3.y);ctx.lineTo(p4.x,p4.y);ctx.closePath();ctx.fill();
ctx.strokeStyle='#441a00';ctx.lineWidth=1;ctx.stroke();
}

// Fire particles
for(let fp of fireParticles){
const p=proj(fp.x,fp.y,fp.z);if(!p)continue;
const a=fp.life/60;ctx.globalAlpha=a;ctx.fillStyle=a>0.5?'#ff4400':'#ff8800';
ctx.fillRect(p.x-2,p.y-2,Math.max(2,p.s*8),Math.max(2,p.s*8));ctx.globalAlpha=1;
}

// Collect all polys for depth sort
let allPolys=[];

// Entities rendering
for(let e of entities){
if(e.type==='enemy'){
const polys=renderModel(enemyVerts,enemyFaces,e.rx,e.ry,0,e.x,e.y,e.z);
allPolys.push(...polys);
}
if(e===boss){
const bverts=enemyVerts;const bfaces=enemyFaces.map(f=>{const nf=[...f];nf[nf.length-1]='#cc0066';return nf});
const polys=renderModel(bverts,bfaces,e.rx,e.ry,0,e.x,e.y,e.z,e.size);
allPolys.push(...polys);
// Boss HP bar
const bp=proj(e.x,e.y-80,e.z);
if(bp){ctx.fillStyle='#330000';ctx.fillRect(bp.x-60,bp.y,120,8);
ctx.fillStyle='#ff0044';ctx.fillRect(bp.x-60,bp.y,120*(e.hp/e.maxHp),8)}
}
if(e.type==='laser'){
const p=proj(e.x,e.y,e.z);if(!p)continue;
ctx.fillStyle='#ff6600';ctx.shadowColor='#ff4400';ctx.shadowBlur=10;
ctx.fillRect(p.x-2,p.y-1,4+p.s*10,2);ctx.shadowBlur=0;
}
if(e.type==='elaser'){
const p=proj(e.x,e.y,e.z);if(!p)continue;
ctx.fillStyle='#ff00ff';ctx.shadowColor='#ff00aa';ctx.shadowBlur=8;
ctx.fillRect(p.x-3,p.y-2,6+p.s*12,4);ctx.shadowBlur=0;
}
if(e.type==='bomb'){
const p=proj(e.x,e.y,e.z);if(!p)continue;
ctx.strokeStyle='#ffaa00';ctx.lineWidth=2;ctx.globalAlpha=e.life/60;
ctx.beginPath();ctx.arc(p.x,p.y,e.radius*p.s,0,Math.PI*2);ctx.stroke();ctx.globalAlpha=1;
}
}

// Player ship
const shipPolys=renderModel(shipVerts,shipFaces,player.rx,player.ry,player.rz,player.x,player.y,player.z);
allPolys.push(...shipPolys);

// Sort and draw
allPolys.sort((a,b)=>b.z-a.z);
for(let p of allPolys)drawPoly(p.pts,p.col);

// Barrel roll flash
if(barrelRoll>0){ctx.fillStyle=`rgba(255,100,0,${barrelRoll/40})`;ctx.fillRect(0,0,W,H)}

// Boss warning
if(bossMode&&boss&&boss.hp>0){
ctx.fillStyle='#ff0022';ctx.font='bold 28px Courier New';ctx.textAlign='center';
if(frame%40<20)ctx.fillText('⛧ DEMON LORD ⛧',cx,60);ctx.textAlign='start';
}
}

let lastTime=0;
function gameLoop(ts){
const dt=Math.min((ts-lastTime)/1000,0.05);lastTime=ts;
update(dt);render();
requestAnimationFrame(gameLoop);
}

document.getElementById('restartBtn').addEventListener('click',init);

// Direct init
init();
lastTime=performance.now();
requestAnimationFrame(gameLoop);
</script>
</body>
</html>
